1 &lt;= nums.length &lt;= 105 -105 &lt;= nums[i] &lt;= 105 1 &lt;= k &lt;= 109 分析 # 题解 # class Solution { public: int shortestSubarray(vector&lt;int&gt;&amp; nums, int k) { } };

