a,&nbsp;b&nbsp;均可能是负数或 0 结果不会溢出 32 位整数 分析 # 题解 # class Solution { public: int add(int a, int b) { } };

 题目 # 难度：Medium
输入一个非负整数数组，把数组里所有数字拼接起来排成一个数，打印能拼接出的所有数字中最小的一个。
&nbsp;
示例 1:
输入: [10,2] 输出: &quot;102&quot; 示例&nbsp;2:
输入: [3,30,34,5,9] 输出: &quot;3033459&quot; &nbsp;
提示:
0 &lt; nums.length &lt;= 100 说明: 输出结果可能非常大，所以你需要返回一个字符串而不是整数 拼接起来的数字可能会有前导 0，最后结果不需要去掉前导 0 分析 # 题解 # class Solution { public: string minNumber(vector&lt;int&gt;&amp; nums) { } };

 题目 # 难度：Easy
从若干副扑克牌中随机抽 5 张牌，判断是不是一个顺子，即这5张牌是不是连续的。2～10为数字本身，A为1，J为11，Q为12，K为13，而大、小王为 0 ，可以看成任意数字。A 不能视为 14。
&nbsp;
示例&nbsp;1:
输入: [1,2,3,4,5] 输出: True &nbsp;
示例&nbsp;2:
输入: [0,0,1,2,5] 输出: True &nbsp;
限制：
数组长度为 5&nbsp;
数组的数取值为 [0, 13] .
分析 # 题解 # class Solution { public: bool isStraight(vector&lt;int&gt;&amp; nums) { } };

 图论 # Floyd算法 # 主要思想是: 循环邻接矩阵中查找每个点到另外一个点的最短距离，不仅是看直接距离，也还要通过计算中转点。比如计算A到B的距离，要比较A到C的距离与C到B的距离的和、A到B的直接距离的最小值来判断，中转点可以是其他节点，所以代码实现中出现了三重循环。
//n为顶点个数 //第一轮循环为 选取中间点的个数 //第二三轮循环为 void floyd(){ for(int k = 1 ; k &lt;=n ; k++) for(int i = 1 ; i &lt;= n ;i ++) for(int j = 1 ; j &lt;=n ;j ++) dic[i][j] = min(dic[i][j],dic[i][k] + dic[k][j]); } 模板题代码：
#include&lt;iostream&gt; using namespace std; const int N = 210,INF = 1e9; int dic[N][N]; int n,m,Q; void floyd(){ for(int k = 1 ; k &lt;=n ; k++) for(int i = 1 ; i &lt;= n ;i ++) for(int j = 1 ; j &lt;=n ;j ++) dic[i][j] = min(dic[i][j],dic[i][k] + dic[k][j]); } int main(){ scanf(&#34;%d%d%d&#34;,&amp;n,&amp;m,&amp;Q); for(int i = 1 ; i &lt;= n ;i ++) for(int j = 1 ; j&lt;=n;j++) if(i == j) dic[i][j] = 0; else dic[i][j] = INF; while(m--) { int a,b,w; scanf(&#34;%d%d%d&#34;,&amp;a,&amp;b,&amp;w); dic[a][b] = min(dic[a][b],w); } floyd(); while(Q--) { int a,b; scanf(&#34;%d%d&#34;,&amp;a,&amp;b); if(dic[a][b] &lt; INF / 2) printf(&#34;%d&#34;,dic[a][b]); else printf(&#34;impossible&#34;); printf(&#34;\n&#34;); } return 0; }

数据结构 # vector[可变数组] # vector是一种变长数组，即可以自动改变长度的数组。 头文件
#include&lt;vector&gt; 初始化
#include&lt;iostream&gt; #include&lt;vector&gt; using namespace std; int main () { //几种初始化的方法 vector&lt;int&gt; a;//定义一个vector 未初始化 输出》 0 vector&lt;int&gt; a(3);//定义一个长度为3的vector 未初始化 输出》0 0 0 vector&lt;int&gt; a(10, 3); //定义一个长度为10，且每个数赋值为3 //将向量b中从下标0 1 2（共三个）的元素赋值给a，a的类型为int型 //它的初始化不和数组一样 vector&lt;int&gt;a(b.begin(),b.begin+3); //从数组中获得初值 int b[7]={1,2,3,4,5,6,7}; vector&lt;int&gt; a(b,b+7）; for(auto x : a) {//遍历输出 cout &lt;&lt; x &lt;&lt; &#34; &#34;; } return 0; } 相关函数
a.size();//返回元素个数 a.resize();//改变大小 a.empty();//判断a是否为空，空则返回true，非空则返回false a.front(); //返回a的第1个元素,当且仅当a存在 a.back(); //返回vector的最后一个数 a.clear(); //清空a中的元素 a.pop_back(); //删除a向量的最后一个元素 a.
